/**
 * Analytics route handlers — framework-agnostic endpoint logic.
 *
 * Each handler accepts a plain params object (parsed from query strings
 * or path params by whatever HTTP framework is wired up), validates
 * inputs, delegates to AnalyticsService, and returns a typed response
 * envelope.
 *
 * Intended mapping (see DESIGN.md):
 *   GET /api/analytics/dashboard       → handleGetDashboard
 *   GET /api/analytics/metrics/:type   → handleGetMetric
 *   GET /api/analytics/top-products    → handleGetTopProducts
 */

import type { AnalyticsService } from '../services/analytics.service.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  TimeGranularity,
  TopProduct,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

// ── Response envelope ────────────────────────────────────────────

export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
}

// ── Raw request param shapes ─────────────────────────────────────

export interface DashboardParams {
  startDate?: string;
  endDate?: string;
  granularity?: string;
}

export interface MetricParams {
  type?: string;
  startDate?: string;
  endDate?: string;
  granularity?: string;
}

export interface TopProductsParams {
  startDate?: string;
  endDate?: string;
  granularity?: string;
  limit?: string;
}

// ── Validation constants ─────────────────────────────────────────

const VALID_GRANULARITIES: ReadonlySet<string> = new Set<TimeGranularity>([
  'hour',
  'day',
  'week',
  'month',
]);

const VALID_METRIC_TYPES: ReadonlySet<string> = new Set<MetricType>([
  'revenue',
  'orders',
  'users',
  'average-order-value',
]);

const MAX_TOP_PRODUCTS_LIMIT = 100;
const DEFAULT_TOP_PRODUCTS_LIMIT = 10;

// ── Route handler class ──────────────────────────────────────────

export class AnalyticsRouteHandler {
  private logger = new Logger('AnalyticsRoutes');

  constructor(private analyticsService: AnalyticsService) {}

  /**
   * GET /api/analytics/dashboard
   *
   * Returns the full dashboard: all KPI summaries, order-status
   * breakdown, and key time series in a single response.
   */
  handleGetDashboard(params: DashboardParams): ApiResponse<DashboardData> {
    try {
      const query = this.parseAnalyticsQuery(params);
      const data = this.analyticsService.getDashboard(query);

      this.logger.info('Dashboard data retrieved successfully');
      return { success: true, data };
    } catch (err) {
      return this.errorResponse(err);
    }
  }

  /**
   * GET /api/analytics/metrics/:type
   *
   * Returns a single metric summary with period-over-period comparison.
   */
  handleGetMetric(params: MetricParams): ApiResponse<MetricSummary> {
    try {
      const metricType = this.parseMetricType(params.type);
      const query = this.parseAnalyticsQuery(params);
      const data = this.analyticsService.getMetric(metricType, query);

      this.logger.info(`Metric '${metricType}' retrieved successfully`);
      return { success: true, data };
    } catch (err) {
      return this.errorResponse(err);
    }
  }

  /**
   * GET /api/analytics/top-products
   *
   * Returns top products ranked by revenue within the queried period.
   */
  handleGetTopProducts(params: TopProductsParams): ApiResponse<TopProduct[]> {
    try {
      const query = this.parseAnalyticsQuery(params);
      const limit = this.parseLimit(params.limit);
      const data = this.analyticsService.getTopProducts(query, limit);

      this.logger.info(`Top ${limit} products retrieved successfully`);
      return { success: true, data };
    } catch (err) {
      return this.errorResponse(err);
    }
  }

  // ── Input parsing & validation ─────────────────────────────────

  private parseAnalyticsQuery(params: {
    startDate?: string;
    endDate?: string;
    granularity?: string;
  }): AnalyticsQuery {
    if (!params.startDate) {
      throw new ValidationError('startDate is required');
    }
    if (!params.endDate) {
      throw new ValidationError('endDate is required');
    }

    const startDate = this.parseDate(params.startDate, 'startDate');
    const endDate = this.parseDate(params.endDate, 'endDate');

    if (startDate > endDate) {
      throw new ValidationError('startDate must not be after endDate');
    }

    const granularity = this.parseGranularity(params.granularity);

    return { startDate, endDate, granularity };
  }

  private parseDate(value: string, fieldName: string): Date {
    const date = new Date(value);
    if (isNaN(date.getTime())) {
      throw new ValidationError(
        `Invalid ${fieldName}: '${value}' is not a valid date`,
      );
    }
    return date;
  }

  private parseGranularity(value?: string): TimeGranularity {
    if (!value) {
      return 'day';
    }
    if (!VALID_GRANULARITIES.has(value)) {
      throw new ValidationError(
        `Invalid granularity: '${value}'. Must be one of: ${[...VALID_GRANULARITIES].join(', ')}`,
      );
    }
    return value as TimeGranularity;
  }

  private parseMetricType(value?: string): MetricType {
    if (!value) {
      throw new ValidationError('Metric type is required');
    }
    if (!VALID_METRIC_TYPES.has(value)) {
      throw new ValidationError(
        `Invalid metric type: '${value}'. Must be one of: ${[...VALID_METRIC_TYPES].join(', ')}`,
      );
    }
    return value as MetricType;
  }

  private parseLimit(value?: string): number {
    if (!value) {
      return DEFAULT_TOP_PRODUCTS_LIMIT;
    }
    const num = Number(value);
    if (!Number.isInteger(num) || num < 1) {
      throw new ValidationError(
        `Invalid limit: '${value}'. Must be a positive integer`,
      );
    }
    if (num > MAX_TOP_PRODUCTS_LIMIT) {
      throw new ValidationError(
        `Limit exceeds maximum of ${MAX_TOP_PRODUCTS_LIMIT}`,
      );
    }
    return num;
  }

  // ── Error formatting ───────────────────────────────────────────

  private errorResponse(err: unknown): ApiResponse<never> {
    if (err instanceof ValidationError) {
      this.logger.warn(`Validation error: ${err.message}`);
      return { success: false, error: err.message };
    }

    const message = err instanceof Error ? err.message : 'Internal server error';
    this.logger.error(`Unexpected error: ${message}`);
    return { success: false, error: message };
  }
}

// ── Validation error type ────────────────────────────────────────

export class ValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ValidationError';
  }
}

