import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { AnalyticsRepository } from '../../src/repositories/analytics.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { AnalyticsRouteHandler, ValidationError } from '../../src/routes/analytics.routes.js';
import type { DashboardParams, MetricParams, TopProductsParams } from '../../src/routes/analytics.routes.js';

describe('AnalyticsRouteHandler', () => {
  let db: Database;
  let handler: AnalyticsRouteHandler;

  const validParams: DashboardParams = {
    startDate: '2026-01-01',
    endDate: '2026-01-31',
    granularity: 'day',
  };

  beforeEach(() => {
    db = new Database();
    const repo = new AnalyticsRepository(db);
    const service = new AnalyticsService(repo);
    handler = new AnalyticsRouteHandler(service);
  });

  function insertOrder(overrides: Record<string, unknown> = {}) {
    const id = overrides['id'] as string ?? `order-${Math.random().toString(36).slice(2)}`;
    db.insert('orders', {
      id,
      userId: 'user-1',
      items: [{ productId: 'prod-1', name: 'Widget', quantity: 2, unitPrice: 25 }],
      total: 50,
      status: 'confirmed',
      createdAt: new Date('2026-01-15').toISOString(),
      updatedAt: new Date('2026-01-15').toISOString(),
      ...overrides,
    });
  }

  function insertUser(overrides: Record<string, unknown> = {}) {
    const id = overrides['id'] as string ?? `user-${Math.random().toString(36).slice(2)}`;
    db.insert('users', {
      id,
      name: 'Test User',
      email: `${id}@test.com`,
      role: 'member',
      createdAt: new Date('2026-01-10').toISOString(),
      updatedAt: new Date('2026-01-10').toISOString(),
      ...overrides,
    });
  }

  // ── handleGetDashboard ─────────────────────────────────────────

  describe('handleGetDashboard', () => {
    it('should return success with valid params', () => {
      const result = handler.handleGetDashboard(validParams);

      expect(result.success).toBe(true);
      expect(result.data).toBeDefined();
      expect(result.data!.metrics).toHaveLength(4);
      expect(result.data!.ordersByStatus).toHaveLength(5);
    });

    it('should return dashboard data with orders', () => {
      insertOrder({ id: 'o1', total: 100 });
      insertOrder({ id: 'o2', total: 200 });

      const result = handler.handleGetDashboard(validParams);

      expect(result.success).toBe(true);
      const revenue = result.data!.metrics.find((m) => m.type === 'revenue');
      expect(revenue!.currentValue).toBe(300);
    });

    it('should default granularity to day when omitted', () => {
      const result = handler.handleGetDashboard({
        startDate: '2026-01-01',
        endDate: '2026-01-31',
      });

      expect(result.success).toBe(true);
      expect(result.data!.query.granularity).toBe('day');
    });

    it('should fail when startDate is missing', () => {
      const result = handler.handleGetDashboard({
        endDate: '2026-01-31',
        granularity: 'day',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('startDate is required');
    });

    it('should fail when endDate is missing', () => {
      const result = handler.handleGetDashboard({
        startDate: '2026-01-01',
        granularity: 'day',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('endDate is required');
    });

    it('should fail when startDate is invalid', () => {
      const result = handler.handleGetDashboard({
        startDate: 'not-a-date',
        endDate: '2026-01-31',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid startDate');
    });

    it('should fail when endDate is invalid', () => {
      const result = handler.handleGetDashboard({
        startDate: '2026-01-01',
        endDate: 'bad',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid endDate');
    });

    it('should fail when startDate is after endDate', () => {
      const result = handler.handleGetDashboard({
        startDate: '2026-02-01',
        endDate: '2026-01-01',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('startDate must not be after endDate');
    });

    it('should fail when granularity is invalid', () => {
      const result = handler.handleGetDashboard({
        startDate: '2026-01-01',
        endDate: '2026-01-31',
        granularity: 'minute',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid granularity');
    });

    it('should accept ISO date strings', () => {
      const result = handler.handleGetDashboard({
        startDate: '2026-01-01T00:00:00.000Z',
        endDate: '2026-01-31T23:59:59.999Z',
        granularity: 'day',
      });

      expect(result.success).toBe(true);
    });
  });

  // ── handleGetMetric ────────────────────────────────────────────

  describe('handleGetMetric', () => {
    it('should return a metric summary for valid params', () => {
      insertOrder({ id: 'o1', total: 100 });

      const result = handler.handleGetMetric({
        type: 'revenue',
        ...validParams,
      });

      expect(result.success).toBe(true);
      expect(result.data!.type).toBe('revenue');
      expect(result.data!.currentValue).toBe(100);
    });

    it('should return all metric types', () => {
      const types = ['revenue', 'orders', 'users', 'average-order-value'] as const;

      for (const type of types) {
        const result = handler.handleGetMetric({ type, ...validParams });
        expect(result.success).toBe(true);
        expect(result.data!.type).toBe(type);
      }
    });

    it('should include period-over-period comparison', () => {
      insertOrder({ id: 'o-prev', total: 100, createdAt: new Date('2025-12-15').toISOString() });
      insertOrder({ id: 'o-curr', total: 150, createdAt: new Date('2026-01-15').toISOString() });

      const result = handler.handleGetMetric({ type: 'revenue', ...validParams });

      expect(result.success).toBe(true);
      expect(result.data!.currentValue).toBe(150);
      expect(result.data!.previousValue).toBe(100);
      expect(result.data!.changePercent).toBe(50);
    });

    it('should fail when type is missing', () => {
      const result = handler.handleGetMetric(validParams as MetricParams);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Metric type is required');
    });

    it('should fail when type is invalid', () => {
      const result = handler.handleGetMetric({
        type: 'invalid-metric',
        ...validParams,
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid metric type');
    });

    it('should fail when date params are missing', () => {
      const result = handler.handleGetMetric({ type: 'revenue' });

      expect(result.success).toBe(false);
      expect(result.error).toContain('startDate is required');
    });
  });

  // ── handleGetTopProducts ───────────────────────────────────────

  describe('handleGetTopProducts', () => {
    it('should return top products for valid params', () => {
      insertOrder({
        id: 'o1',
        items: [
          { productId: 'p1', name: 'Widget A', quantity: 5, unitPrice: 10 },
          { productId: 'p2', name: 'Widget B', quantity: 1, unitPrice: 100 },
        ],
        total: 150,
      });

      const result = handler.handleGetTopProducts(validParams as TopProductsParams);

      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(2);
      expect(result.data![0].productId).toBe('p2');
      expect(result.data![0].totalRevenue).toBe(100);
    });

    it('should use default limit of 10', () => {
      const items = Array.from({ length: 15 }, (_, i) => ({
        productId: `p${i}`,
        name: `Product ${i}`,
        quantity: 1,
        unitPrice: (15 - i) * 10,
      }));
      insertOrder({ id: 'o1', items, total: 1200 });

      const result = handler.handleGetTopProducts(validParams as TopProductsParams);

      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(10);
    });

    it('should respect custom limit', () => {
      const items = Array.from({ length: 5 }, (_, i) => ({
        productId: `p${i}`,
        name: `Product ${i}`,
        quantity: 1,
        unitPrice: 10,
      }));
      insertOrder({ id: 'o1', items, total: 50 });

      const result = handler.handleGetTopProducts({
        ...validParams,
        limit: '3',
      });

      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(3);
    });

    it('should fail for non-integer limit', () => {
      const result = handler.handleGetTopProducts({
        ...validParams,
        limit: '3.5',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid limit');
    });

    it('should fail for zero limit', () => {
      const result = handler.handleGetTopProducts({
        ...validParams,
        limit: '0',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid limit');
    });

    it('should fail for negative limit', () => {
      const result = handler.handleGetTopProducts({
        ...validParams,
        limit: '-5',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid limit');
    });

    it('should fail for limit exceeding maximum', () => {
      const result = handler.handleGetTopProducts({
        ...validParams,
        limit: '101',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Limit exceeds maximum');
    });

    it('should fail for non-numeric limit', () => {
      const result = handler.handleGetTopProducts({
        ...validParams,
        limit: 'abc',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid limit');
    });

    it('should return empty array when no orders exist', () => {
      const result = handler.handleGetTopProducts(validParams as TopProductsParams);

      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(0);
    });
  });

  // ── ValidationError ────────────────────────────────────────────

  describe('ValidationError', () => {
    it('should be an instance of Error', () => {
      const err = new ValidationError('test');
      expect(err).toBeInstanceOf(Error);
      expect(err.name).toBe('ValidationError');
      expect(err.message).toBe('test');
    });
  });

  // ── Response envelope shape ────────────────────────────────────

  describe('response envelope', () => {
    it('should include success: true and data on success', () => {
      const result = handler.handleGetDashboard(validParams);

      expect(result).toHaveProperty('success', true);
      expect(result).toHaveProperty('data');
      expect(result).not.toHaveProperty('error');
    });

    it('should include success: false and error on failure', () => {
      const result = handler.handleGetDashboard({});

      expect(result).toHaveProperty('success', false);
      expect(result).toHaveProperty('error');
    });
  });
});

